def sanitize_label_value(value, max_length=128):
    """Sanitize a string to be safe for use as a Prometheus label value."""
    if not isinstance(value, str):
        value = str(value)
    # Remove any characters that could cause issues in Prometheus labels
    sanitized = re.sub(r'[^\w\-_./]', '_', value)
    return sanitized[:max_length]


def sanitize_endpoint(endpoint):
    """
    Sanitize and normalize endpoint paths to prevent label cardinality explosion.
    Only allow known endpoints; unknown ones get mapped to 'unknown'.
    """
    # Define an explicit allowlist of known endpoint patterns
    known_endpoints = {
        "/": "/",
        "/health": "/health",
        "/api/data": "/api/data",
        "/api/process": "/api/process",
        "/metrics": "/metrics",
    }

    # Parameterized route patterns
    parameterized_patterns = [
        (re.compile(r"^/api/items/\d+$"), "/api/items/:id"),
        (re.compile(r"^/api/users/\d+$"), "/api/users/:id"),
    ]

    if endpoint in known_endpoints:
        return known_endpoints[endpoint]

    for pattern, normalized in parameterized_patterns:
        if pattern.match(endpoint):
            return normalized

    return "/unknown"


def constant_time_compare(val1, val2):
    """Perform constant-time string comparison to prevent timing attacks."""
    return hmac.compare_digest(
        val1.encode("utf-8") if isinstance(val1, str) else val1,
        val2.encode("utf-8") if isinstance(val2, str) else val2,
    )


